import { Plus, Search, Filter, Grid, List } from 'lucide-react';

export default function PatientsView() {
  return (
    <div className="p-8 h-full overflow-auto bg-gray-50">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Patients</h1>
          <p className="text-gray-600 mt-1">Manage and monitor your patients</p>
        </div>
        <button className="flex items-center gap-2 bg-purple-600 text-white px-6 py-3 rounded-lg hover:bg-purple-700 transition-colors font-semibold">
          <Plus size={20} />
          Add Patient
        </button>
      </div>

      {/* Search and Filters */}
      <div className="flex items-center gap-4 mb-6">
        <div className="flex-1 relative">
          <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
          <input
            type="text"
            placeholder="Search patients..."
            className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-lg focus:outline-none focus:border-purple-400 transition-colors"
          />
        </div>
        <button className="flex items-center gap-2 px-4 py-3 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors">
          <Filter size={20} className="text-gray-600" />
          <span className="text-gray-700 font-medium">Filters</span>
        </button>
        <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-lg p-1">
          <button className="p-2 bg-purple-600 text-white rounded-md">
            <Grid size={20} />
          </button>
          <button className="p-2 text-gray-600 hover:bg-gray-100 rounded-md">
            <List size={20} />
          </button>
        </div>
      </div>

      {/* Patient Count */}
      <p className="text-gray-600 mb-8">Showing 0 patients</p>

      {/* Empty State */}
      <div className="flex flex-col items-center justify-center py-20">
        <p className="text-gray-500 text-lg mb-6">No patients found</p>
        <button className="px-6 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition-colors">
          Clear search
        </button>
      </div>
    </div>
  );
}
